/**
 * probe-tokenizer-gguf.ts — verify a tokenizer-only GGUF parses with the
 * SAME loader the consolidated mesh uses (loadQwenTokenizerFromGguf).
 *
 * Usage:
 *   pnpm run gnode -- run open-source/gnosis/distributed-inference-host/scripts/probe-tokenizer-gguf.ts <gguf-path> [expected-vocab]
 */
import { loadQwenTokenizerFromGguf } from '../src/qwen-tokenizer';

const ggufPath = process.argv[2];
const expected = process.argv[3] ? Number(process.argv[3]) : undefined;
if (!ggufPath) {
  console.error('usage: probe-tokenizer-gguf.ts <gguf-path> [expected-vocab]');
  process.exit(2);
}

const tok = loadQwenTokenizerFromGguf(ggufPath);
// QwenTokenizer keeps idToToken private; encode a probe string instead.
const sample = 'Hello, world! The quick brown fox jumps over the lazy dog.';
const ids = tok.encode(sample);
const round = tok.decode(ids);

console.log(JSON.stringify({
  path: ggufPath,
  stopTokenIds: tok.stopTokenIds,
  sample,
  encodedLen: ids.length,
  firstIds: ids.slice(0, 12),
  decoded: round,
  roundtripOk: round === sample,
  expectedVocab: expected ?? null,
}, null, 2));

if (ids.length === 0) {
  console.error('FAIL: empty encoding');
  process.exit(1);
}
if (round !== sample) {
  console.error('WARN: roundtrip mismatch (may be benign for byte-level edge cases)');
}
console.log('PROBE OK');
